VALUES
  ('optometrist-moex-00054', 'optometrist', 'optometrist-moex-114-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關淚液系統之敘述，下列何者正確？', '["淚液大致分三層：水分層、黏液層與油脂層，黏液層由麥氏腺（meibomiangland）所分泌", "成人鼻淚管長度大約12mm，開口位在中鼻甲，故滴眼藥水在眼部可能經此進到鼻腔而有全身作用", "Schirmer’s淚液測試（Schirmer’stest）可偵測淚液所有成分的量是否足夠，若偵測值小於10mm表示淚 液量不足", "結膜含有可分泌淚液中水分層及黏液層的腺體，故長期感染可造成乾眼症狀"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:39+00:00", "source_pdf_sha1": "a07a9f0fc159", "answer_pdf_sha1": "e918d93fe3c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00055', 'optometrist', 'optometrist-moex-114-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '下列那些神經穿過辛氏腱環（annulusofZinn）進入眼窩？①顏面神經  ②鼻睫狀神經  ③外展神經  ④淚 腺神經  ⑤滑車神經  ⑥動眼神經', '["", "", "⑥", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:39+00:00", "source_pdf_sha1": "a07a9f0fc159", "answer_pdf_sha1": "e918d93fe3c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00056', 'optometrist', 'optometrist-moex-114-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關淚腺（lacrimalgland）的敘述，下列何者錯誤？', '["淚腺位於眼眶外上側的淚腺窩", "眼輪匝肌（orbicularisoculimuscle）將淚腺分隔為眼眶區（orbitalportion）和眼瞼區（palpebralportion） 兩葉", "淚腺分泌最主要經由顏面神經的副交感纖維所控制", "淚腺的感覺神經經由三叉神經傳導"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:39+00:00", "source_pdf_sha1": "a07a9f0fc159", "answer_pdf_sha1": "e918d93fe3c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00057', 'optometrist', 'optometrist-moex-114-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '關於眼角膜構造，下列何者錯誤？', '["角膜內皮細胞數在年輕成人大概有3,000cells/mm2", "角膜內皮細胞數隨著年齡的增加每年約流失 0.6%，而流失的角膜內皮細胞其鄰近內皮細胞會變小 （neighbouringcellsshrinkage）", "角膜內皮細胞低於500cells/mm2，可能引起角膜水腫", "中心角膜的厚度跟性別無關（doesnotdifferbetweenmalesandfemales），但與種族有關（variesbetween races）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:39+00:00", "source_pdf_sha1": "a07a9f0fc159", "answer_pdf_sha1": "e918d93fe3c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00058', 'optometrist', 'optometrist-moex-114-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '角膜的構造可分為五層，其由眼外到內的順序為：①表皮層（epitheliallayer）  ②鮑曼氏層（Bowman’slayer）', '["德式密氏膜（Descemet’smembrane）", "內皮細胞層（endotheliallayer）  ⑤基質層（stromallayer）", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:39+00:00", "source_pdf_sha1": "a07a9f0fc159", "answer_pdf_sha1": "e918d93fe3c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00059', 'optometrist', 'optometrist-moex-114-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '眼內何處會排出房水？①角膜基質細胞  ②葡萄膜鞏膜路徑  ③前房小樑  ④視網膜', '["僅", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:39+00:00", "source_pdf_sha1": "a07a9f0fc159", "answer_pdf_sha1": "e918d93fe3c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
