  ('optometrist-moex-00061', 'optometrist', 'optometrist-moex-114-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關葡萄膜（uvea）之敘述，下列何者錯誤？', '["葡萄膜包括脈絡膜、睫狀體和虹膜", "前葡萄膜炎即虹彩炎，可產生虹膜前粘連和虹膜後粘連，導致高眼壓或青光眼發生", "交感性眼炎是一種罕見但具有破壞性的單側肉芽腫性葡萄膜炎", "葡萄膜炎會使水晶體增厚或混濁，導致白內障發生"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:39+00:00", "source_pdf_sha1": "a07a9f0fc159", "answer_pdf_sha1": "e918d93fe3c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00062', 'optometrist', 'optometrist-moex-114-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '下列何處為玻璃體與內限膜（internallimitingmembrane）最緊密連結的位置？①玻璃體於眼球赤道處', '["玻璃體與視神經盤交界處", "玻璃體於格子狀退化處", "玻璃體與黃斑凹附近500 μm範圍", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:39+00:00", "source_pdf_sha1": "a07a9f0fc159", "answer_pdf_sha1": "e918d93fe3c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00063', 'optometrist', 'optometrist-moex-114-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '下列何種細胞連結方式使視網膜色素上皮細胞具血液視網膜屏障（blood-retinabarrier）之功能？', '["間隙細胞連結（gapjunction）", "錨定細胞連結（anchoringjunction）", "緊密細胞連結（tightjunction）", "原生質絲（plasmodesmata）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:39+00:00", "source_pdf_sha1": "a07a9f0fc159", "answer_pdf_sha1": "e918d93fe3c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
